import{_ as n,r as d,o as t,a as s,b as a,d as i,F as l,c as o,e}from"./app.56afa649.js";const m={},h=o('<h1 id="gravar" tabindex="-1"><a class="header-anchor" href="#gravar" aria-hidden="true">#</a> Gravar</h1><h2 id="graves" tabindex="-1"><a class="header-anchor" href="#graves" aria-hidden="true">#</a> Graves</h2><p>N\xE4r man d\xF6r skapas en grav p\xE5 platsen.<br> Denna inneh\xE5ller dina f\xF6rem\xE5l och eventuell XP. <em>(N\xE4r man d\xF6r droppar man inte all sin XP utan en stor del f\xF6rsvinner)</em><br> Om du st\xE5r n\xE4ra en grav kan du se vem som \xE4ger den.</p><p>Om man d\xF6r flera g\xE5nger s\xE5 spawnas nya gravar.<br> Du kan ha obegr\xE4nsat antal spawnade gravar men f\xF6rem\xE5len du hade p\xE5 dig n\xE4r du d\xF6r hamnar i graven som spawnas p\xE5 platsen.<br> Dom flyttas allts\xE5 inte till n\xE4sta grav.</p><p>PS: Om chunken inte \xE4r inladdad, t. ex. n\xE4r man d\xF6r i en annan v\xE4rld d\xE4r ingen \xE4r, s\xE5 r\xE4knas inte tiden.</p><div class="custom-container warning"><p class="custom-container-title">VARNING</p><p>Varje grav finns kvar i 10 minuter fr\xE5n d\xF6dsfallet.<br> Om chunken \xE4r inladdad s\xE5 kommer graven f\xF6rsvinna efter dessa 10 minuter och man kan inte l\xE4ngre \xE5terf\xE5 sina f\xF6rem\xE5l.</p></div><h2 id="plats" tabindex="-1"><a class="header-anchor" href="#plats" aria-hidden="true">#</a> Plats</h2><p>Koordinaterna till graven f\xE5r man i chatten vid d\xF6dsfallet och man kan \xE4ven se dem i TAB-listan.</p><div class="custom-container tip"><p class="custom-container-title">TIPS</p><p>Ta en printscreen eller skriv ner koordinaterna s\xE5 du har sparat platsen med dina viktiga f\xF6rem\xE5l om du d\xF6r fler g\xE5nger.</p></div><h2 id="dodsorsaker-gravplats" tabindex="-1"><a class="header-anchor" href="#dodsorsaker-gravplats" aria-hidden="true">#</a> D\xF6dsorsaker &amp; gravplats</h2><ul><li>Om du d\xF6r i void <em>(world_the_end)</em> s\xE5 kommer din grav spawna p\xE5 ett gr\xE4sblock precis ovanf\xF6r void. Denna kan man sedan g\xE5/flyga till f\xF6r att f\xE5 tillbaka sina saker.</li><li>Om du d\xF6r i luften kommer din grav hamna p\xE5 marken.</li><li>Om du d\xF6r i lava kommer din grav hamna p\xE5 ytan.</li><li>Om du d\xF6r ovanf\xF6r eller i vatten kommer din grav spawna p\xE5 botten.</li><li>Om du d\xF6r inuti ett block kommer din grav hamna ovanp\xE5 detta block.</li><li>Om du d\xF6r p\xE5 samma plats som en annan grav kommer din grav hamna ovanp\xE5 den.</li></ul><h2 id="hamta-foremal" tabindex="-1"><a class="header-anchor" href="#hamta-foremal" aria-hidden="true">#</a> H\xE4mta f\xF6rem\xE5l</h2><p>N\xE4r du har hittat din grav s\xE5 kan du h\xF6gerklicka p\xE5 den med en tom hand. D\xE5 sl\xE4pps f\xF6rem\xE5len fria och du kan plocka upp dem.<br> Om du hukar dig samtidigt som du h\xF6gerklickar p\xE5 graven s\xE5 kan endast du plocka upp f\xF6rem\xE5len.</p><h2 id="hojdgranser" tabindex="-1"><a class="header-anchor" href="#hojdgranser" aria-hidden="true">#</a> H\xF6jdgr\xE4nser</h2><p>H\xF6jdgr\xE4nsen har expanderats med 64 blocks upp och 64 blocks ner.<br> Maxh\xF6jd upp\xE5t: Y=319<br> Maxgr\xE4ns ned\xE5t: Y=-64</p><h2 id="foremal" tabindex="-1"><a class="header-anchor" href="#foremal" aria-hidden="true">#</a> F\xF6rem\xE5l</h2>',16),p=e("Med detta kan man crafta "),c={href:"https://minecraft.fandom.com/wiki/Bundle",target:"_blank",rel:"noopener noreferrer"},u=e("bundle");function v(g,k){const r=d("ExternalLinkIcon");return t(),s(l,null,[h,a("p",null,[p,a("a",c,[u,i(r)])])],64)}var b=n(m,[["render",v],["__file","datapacks.html.vue"]]);export{b as default};
